const fs = require("fs")
const path = require("path")

const ROOT = process.cwd()
const GENERATED_WRAPPER_HEADER = "// Generated by scripts/generate-data-layer.cjs. Do not edit by hand."
const GENERATED_STUB_HEADER =
  "// Generated by scripts/generate-data-layer.cjs. Replace stubs with real Supabase implementations module by module."
const EXTENSIONS = new Set([".ts", ".tsx", ".js", ".jsx", ".cjs", ".mjs"])

const OUTPUT_JSON = path.join(ROOT, "docs", "data-layer-coverage.generated.json")
const OUTPUT_MD = path.join(ROOT, "docs", "data-layer-coverage.generated.md")

function ensureDir(dirPath) {
  fs.mkdirSync(dirPath, { recursive: true })
}

function walkFiles(startDir) {
  const results = []
  if (!fs.existsSync(startDir)) return results

  for (const entry of fs.readdirSync(startDir, { withFileTypes: true })) {
    const fullPath = path.join(startDir, entry.name)
    if (entry.isDirectory()) {
      if (entry.name === "node_modules" || entry.name === "dist") continue
      results.push(...walkFiles(fullPath))
      continue
    }
    if (EXTENSIONS.has(path.extname(entry.name))) {
      results.push(fullPath)
    }
  }

  return results
}

function extractExports(source) {
  const names = []
  const seen = new Set()
  const patterns = [
    /^export\s+(?:async\s+)?function\s+([A-Za-z0-9_]+)/gm,
    /^export\s+const\s+([A-Za-z0-9_]+)/gm,
    /^export\s+let\s+([A-Za-z0-9_]+)/gm,
    /^export\s+var\s+([A-Za-z0-9_]+)/gm,
  ]

  for (const pattern of patterns) {
    let match
    while ((match = pattern.exec(source)) !== null) {
      const name = match[1]
      if (!seen.has(name)) {
        seen.add(name)
        names.push(name)
      }
    }
  }

  const exportListRe = /^export\s*\{\s*([^}]+)\s*\}/gm
  let listMatch
  while ((listMatch = exportListRe.exec(source)) !== null) {
    const entries = listMatch[1]
      .split(",")
      .map((item) => item.trim())
      .filter(Boolean)
      .map((item) => item.split(/\s+as\s+/i)[1] || item.split(/\s+as\s+/i)[0])

    for (const name of entries) {
      if (!seen.has(name)) {
        seen.add(name)
        names.push(name)
      }
    }
  }

  return names
}

function unique(values) {
  return [...new Set(values)]
}

function toPosix(filePath) {
  return path.relative(ROOT, filePath).split(path.sep).join("/")
}

function gatherModuleCoverage(label, rtdbDir, dataDir, providerDir) {
  if (!fs.existsSync(rtdbDir)) {
    return {
      label,
      moduleCount: 0,
      exportCount: 0,
      dataFacadeParityOk: true,
      providerMirrorParityOk: true,
      modules: [],
    }
  }

  const files = fs
    .readdirSync(rtdbDir)
    .filter((name) => /\.(ts|tsx)$/.test(name))
    .sort()

  const modules = files.map((fileName) => {
    const moduleName = path.basename(fileName, path.extname(fileName))
    const rtdbPath = path.join(rtdbDir, fileName)
    const dataPath = path.join(dataDir, `${moduleName}.ts`)
    const providerPath = path.join(providerDir, `${moduleName}.ts`)

    const rtdbSource = fs.readFileSync(rtdbPath, "utf8")
    const rtdbExports = extractExports(rtdbSource)

    const dataExists = fs.existsSync(dataPath)
    const dataSource = dataExists ? fs.readFileSync(dataPath, "utf8") : ""
    const dataExports = dataExists ? extractExports(dataSource) : []
    const missingInData = rtdbExports.filter((name) => !dataExports.includes(name))

    const providerExists = fs.existsSync(providerPath)
    const providerSource = providerExists ? fs.readFileSync(providerPath, "utf8") : ""
    const providerExplicitExports = providerExists ? extractExports(providerSource) : []
    const providerHasExportStar = providerExists && new RegExp(`export\\s+\\*\\s+from\\s+["'][^"']*rtdatabase\\/${moduleName}["']`).test(providerSource)
    const providerMirroredExports = providerHasExportStar
      ? unique([...rtdbExports, ...providerExplicitExports])
      : providerExplicitExports
    const missingInProvider = rtdbExports.filter((name) => !providerMirroredExports.includes(name))

    let providerMode = "missing"
    if (providerExists) {
      if (providerSource.startsWith(GENERATED_STUB_HEADER)) providerMode = "stub"
      else if (providerHasExportStar) providerMode = "manual-passthrough"
      else providerMode = "manual"
    }

    return {
      name: moduleName,
      rtdbFile: toPosix(rtdbPath),
      dataFile: dataExists ? toPosix(dataPath) : null,
      providerFile: providerExists ? toPosix(providerPath) : null,
      rtdbExportCount: rtdbExports.length,
      dataExportCount: dataExports.length,
      providerExplicitExportCount: providerExplicitExports.length,
      providerMirroredExportCount: providerMirroredExports.length,
      dataFacadeParityOk: missingInData.length === 0,
      providerMirrorParityOk: missingInProvider.length === 0,
      missingInData,
      missingInProvider,
      providerMode,
      dataWrapperGenerated: dataExists && dataSource.startsWith(GENERATED_WRAPPER_HEADER),
      providerHasExportStar,
      nativeOverrideCount:
        providerMode === "manual" || providerMode === "manual-passthrough" ? providerExplicitExports.length : 0,
    }
  })

  return {
    label,
    moduleCount: modules.length,
    exportCount: modules.reduce((sum, moduleInfo) => sum + moduleInfo.rtdbExportCount, 0),
    dataFacadeParityOk: modules.every((moduleInfo) => moduleInfo.dataFacadeParityOk),
    providerMirrorParityOk: modules.every((moduleInfo) => moduleInfo.providerMirrorParityOk),
    modules,
  }
}

function gatherMobileConsideration() {
  const mobileRoot = path.join(ROOT, "mobile")
  const files = walkFiles(mobileRoot)
  const importRe = /backend\/(?:rtdatabase|data)\/([A-Za-z0-9_-]+)/g
  const dataDomainRe = /\/data\/([A-Za-z0-9_-]+)/g

  const directImports = []
  const rawDomainsByFile = {}

  for (const filePath of files) {
    const source = fs.readFileSync(filePath, "utf8")
    const sourceWithoutImports = source
      .split(/\r?\n/)
      .filter((line) => !line.trim().startsWith("import "))
      .join("\n")

    let match
    while ((match = importRe.exec(source)) !== null) {
      directImports.push({
        file: toPosix(filePath),
        module: match[1],
      })
    }

    const domains = new Set()
    while ((match = dataDomainRe.exec(sourceWithoutImports)) !== null) {
      domains.add(match[1])
    }
    if (domains.size) {
      rawDomainsByFile[toPosix(filePath)] = [...domains].sort()
    }
  }

  const directImportModules = unique(directImports.map((entry) => entry.module)).sort()
  const rawDomains = unique(
    Object.values(rawDomainsByFile).flatMap((domains) => domains),
  ).sort()

  return {
    directImportCount: directImports.length,
    directImportModules,
    directImports,
    rawDataPathFileCount: Object.keys(rawDomainsByFile).length,
    rawDataDomains: rawDomains,
    rawDomainsByFile,
  }
}

function createMarkdown(report) {
  const lines = [
    "# Data Layer Coverage Audit",
    "",
    `Generated: ${report.generatedAt}`,
    "",
    "## App",
    "",
    `- Modules: ${report.app.moduleCount}`,
    `- RTDB exports: ${report.app.exportCount}`,
    `- Data facade parity: ${report.app.modules.filter((moduleInfo) => moduleInfo.dataFacadeParityOk).length}/${report.app.moduleCount} modules complete`,
    `- Provider mirror parity: ${report.app.modules.filter((moduleInfo) => moduleInfo.providerMirrorParityOk).length}/${report.app.moduleCount} modules complete`,
    `- Manual provider modules: ${
      report.app.modules.filter((moduleInfo) => moduleInfo.providerMode !== "stub").map((moduleInfo) => moduleInfo.name).join(", ") || "none"
    }`,
    `- Stub-only provider modules: ${
      report.app.modules.filter((moduleInfo) => moduleInfo.providerMode === "stub").map((moduleInfo) => moduleInfo.name).join(", ") || "none"
    }`,
    "",
    "## Admin",
    "",
    `- Modules: ${report.admin.moduleCount}`,
    `- RTDB exports: ${report.admin.exportCount}`,
    `- Data facade parity: ${report.admin.modules.filter((moduleInfo) => moduleInfo.dataFacadeParityOk).length}/${report.admin.moduleCount} modules complete`,
    `- Provider mirror parity: ${report.admin.modules.filter((moduleInfo) => moduleInfo.providerMirrorParityOk).length}/${report.admin.moduleCount} modules complete`,
    `- Manual provider modules: ${
      report.admin.modules.filter((moduleInfo) => moduleInfo.providerMode !== "stub").map((moduleInfo) => moduleInfo.name).join(", ") || "none"
    }`,
    `- Stub-only provider modules: ${
      report.admin.modules.filter((moduleInfo) => moduleInfo.providerMode === "stub").map((moduleInfo) => moduleInfo.name).join(", ") || "none"
    }`,
    "",
    "## Mobile",
    "",
    `- Direct imports of app/admin RTDB or data modules: ${report.mobile.directImportCount}`,
    `- Directly imported modules: ${report.mobile.directImportModules.join(", ") || "none"}`,
    `- Files with raw /data/... path usage: ${report.mobile.rawDataPathFileCount}`,
    `- Raw data domains referenced: ${report.mobile.rawDataDomains.join(", ") || "none"}`,
    "",
    "## App Module Detail",
    "",
  ]

  for (const moduleInfo of report.app.modules) {
    lines.push(`- ${moduleInfo.name}: facade ${moduleInfo.rtdbExportCount}/${moduleInfo.rtdbExportCount}, provider ${moduleInfo.providerMirroredExportCount}/${moduleInfo.rtdbExportCount}, mode ${moduleInfo.providerMode}, native overrides ${moduleInfo.nativeOverrideCount}`)
    if (moduleInfo.missingInData.length) {
      lines.push(`  missing in data: ${moduleInfo.missingInData.join(", ")}`)
    }
    if (moduleInfo.missingInProvider.length) {
      lines.push(`  missing in provider: ${moduleInfo.missingInProvider.join(", ")}`)
    }
  }

  lines.push("", "## Admin Module Detail", "")

  for (const moduleInfo of report.admin.modules) {
    lines.push(`- ${moduleInfo.name}: facade ${moduleInfo.rtdbExportCount}/${moduleInfo.rtdbExportCount}, provider ${moduleInfo.providerMirroredExportCount}/${moduleInfo.rtdbExportCount}, mode ${moduleInfo.providerMode}, native overrides ${moduleInfo.nativeOverrideCount}`)
    if (moduleInfo.missingInData.length) {
      lines.push(`  missing in data: ${moduleInfo.missingInData.join(", ")}`)
    }
    if (moduleInfo.missingInProvider.length) {
      lines.push(`  missing in provider: ${moduleInfo.missingInProvider.join(", ")}`)
    }
  }

  lines.push("", "## Mobile Raw Path Detail", "")

  if (!Object.keys(report.mobile.rawDomainsByFile).length) {
    lines.push("- none")
  } else {
    for (const [file, domains] of Object.entries(report.mobile.rawDomainsByFile)) {
      lines.push(`- ${file}: ${domains.join(", ")}`)
    }
  }

  return `${lines.join("\n").trim()}\n`
}

function main() {
  const report = {
    generatedAt: new Date().toISOString(),
    app: gatherModuleCoverage(
      "app",
      path.join(ROOT, "app", "backend", "rtdatabase"),
      path.join(ROOT, "app", "backend", "data"),
      path.join(ROOT, "app", "backend", "providers", "supabase"),
    ),
    admin: gatherModuleCoverage(
      "admin",
      path.join(ROOT, "admin", "backend", "rtdatabase"),
      path.join(ROOT, "admin", "backend", "data"),
      path.join(ROOT, "admin", "backend", "providers", "supabase"),
    ),
    mobile: gatherMobileConsideration(),
  }

  ensureDir(path.dirname(OUTPUT_JSON))
  fs.writeFileSync(OUTPUT_JSON, `${JSON.stringify(report, null, 2)}\n`, "utf8")
  fs.writeFileSync(OUTPUT_MD, createMarkdown(report), "utf8")

  console.log(`Coverage audit written to ${path.relative(ROOT, OUTPUT_JSON)}`)
  console.log(`Coverage audit written to ${path.relative(ROOT, OUTPUT_MD)}`)
  console.log(
    `App parity: ${report.app.modules.filter((moduleInfo) => moduleInfo.dataFacadeParityOk && moduleInfo.providerMirrorParityOk).length}/${report.app.moduleCount}`,
  )
  console.log(
    `Admin parity: ${report.admin.modules.filter((moduleInfo) => moduleInfo.dataFacadeParityOk && moduleInfo.providerMirrorParityOk).length}/${report.admin.moduleCount}`,
  )
  console.log(`Mobile direct imports: ${report.mobile.directImportCount}`)
}

main()
